// PATTERN BANK: Acid 303 Bass
// Classic squelchy acid line for breakdowns
setcps(138/60/4)
let acidFilter = slider(800, 200, 4000, 10, "ACID Filter")
let acidRes = slider(18, 5, 25, 0.5, "ACID Resonance")
let acidVol = slider(0.6, 0, 1, 0.01, "ACID Volume")

let acid = note("<a2 a2 c3 a2 e2 e2 g2 e2>")
  .s("sawtooth")
  .cutoff(sine.range(300, acidFilter).fast(2))
  .resonance(acidRes)
  .decay(0.15)
  .sustain(0)
  .gain(acidVol)
  .struct("x x [x x] x x [~ x] x x")

let kick = s("bd").bank("RolandTR909").gain(1.1).struct("x x x x")
let hats = s("hh").bank("RolandTR909").gain(0.4).struct("~ x ~ x ~ x ~ x")

stack(kick, hats, acid)
